def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 5:
            for a in range(5, 0, -1):
                for b in range(1, a + 1):
                    penalty = ((ratio - a) ** 2) * np.cos(ratio * b / (a + 1))
                    priority += penalty / (a * b)
            priority += np.exp(ratio - 5) * np.sin(ratio)
        elif 3 < ratio <= 5:
            for m in range(1, int(np.ceil(ratio)) + 2):
                val = (ratio - m) ** 2
                val *= np.log1p(m * ratio) if m != 0 else 1
                priority += val * np.tanh(ratio / (m+1))
            priority += np.sqrt(ratio) * 10
        elif 1 < ratio <= 3:
            temp_sum = 0
            for k in range(1, 7):
                temp_sum += ((ratio - 1) ** k) / (k * 2)
            priority = temp_sum + np.sin(5 * ratio) * np.log(ratio + 1)
            if int(item) % 2 == 0 and bin_cap % 3 == 0:
                priority *= 1.2
            else:
                priority *= 0.8
        elif 0.5 <= ratio <= 1:
            priority = -np.log(ratio) * 4 + np.tanh(10 * (1 - ratio))
            for c in range(2, 6):
                priority += ((1 - ratio) ** c) / (c * np.e)
            if bin_cap < item:
                priority += np.log1p(bin_cap) * 3
        elif 0.2 <= ratio < 0.5:
            helper = 0
            for n in range(1, 8):
                helper += ((0.5 - ratio) ** n) / n
            correction = np.cos(20 * ratio) * np.exp(-ratio)
            if bin_cap < item * 0.7:
                priority = helper + correction + np.sqrt(bin_cap) / (item + 1)
            else:
                priority = helper - correction
        else:
            base_priority = 1 / (bin_cap + 1)
            decay = 0
            for d in range(1, 10):
                decay += ((0.2 - ratio) ** d) / (d * 3)
            priority = base_priority + decay
            if int(item) % 3 == 0:
                priority *= 1.7
            else:
                priority /= 1.7
            if bin_cap < item * 0.3:
                priority += np.sin(bin_cap) * np.log1p(item)
        if bin_cap < item * 0.4:
            priority += np.log1p(item * bin_cap) * 3
        elif bin_cap > item * 3:
            priority -= np.exp(-ratio) * 2
        priorities[i] = priority
    return priorities
